"""
MKT Original Language Commentary — 1 Chronicles chapters 23–25
Run: python3 scripts/zc-original-1chronicles-23-25.py

Ch23: Levitical organization for the temple; age-shift from 30 to 20 (vv24-27);
      the standing/ministering vocabulary (laʿamod, šārat, yᵉhallel/bārak)
Ch24: 24 priestly courses by lot (gôrāl) — Abijah 8th (v10) = Zechariah's course (Luke 1:5);
      priestly succession through Eleazar/Ithamar after Nadab/Abihu die without sons
Ch25: Temple musicians called "prophets" (hannibbĕʾîm, v1); Heman as ḥōzeh (seer);
      talmîḏ (disciple/student, rare OT term) in the lot instructions (v8);
      288 = 24 × 12 structural symmetry with the priestly courses

Key decisions:
- naṣṣēaḥ (v4): "oversee" — same root as the lᵉmnaṣṣēaḥ psalm superscription (to the director)
- ʾîš hāʾĕlōhîm for Moses (v14): the "man of God" title used for prophets, not priests
- gôrāl (lots, ch 24-25): theologically significant — the lot is YHWH's determination, not human preference
- nāḇāʾ for musicians (25:1-3): prophetic status of temple worship music
- ʿal-yᵉḏê (25:2): "under the hands of" = under the direction of; idiom for authority
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRON1 = {
  "23": {
    "1": "<p><strong>z&amacr;q&ecirc;n wĕś&amacr;ḇaʿ y&amacr;m&icirc;m</strong> &mdash; &lsquo;old and full of days&rsquo; (lit. &lsquo;satisfied with days&rsquo;). The identical phrase is used of Abraham (Gen 25:8) and Isaac (Gen 35:29). The Chronicler frames David&rsquo;s final acts with the same formula used for the great patriarchs, elevating his organizational preparations to the rank of covenant-constitutive acts. What follows in chs. 23&ndash;27 is David&rsquo;s ecclesiastical and civil legacy to Solomon &mdash; the organization of Israel&rsquo;s institutional life as the counterpart to Solomon&rsquo;s construction of the temple.</p>",
    "2": "<p>David gathers all the leaders (<em>k&amacr;l-ś&amacr;r&ecirc;</em>), the priests (<em>hakk&ocirc;h&breve;n&icirc;m</em>), and the Levites (<em>hallĕw&icirc;yim</em>). The three-part assembly &mdash; civil leaders, priests, Levites &mdash; corresponds to the three institutional streams that will govern temple-centered Israel. The assembly for the organizational decree parallels the assembly at Sinai (Exod 19-20) where YHWH assembled Israel to give the law; here David assembles Israel to give the institutional structure for the law&rsquo;s worship expression.</p>",
    "3": "<p><strong>wayyipp&amacr;q&breve;ḏ&ucirc;</strong> (Niphal of <em>p&amacr;qaḏ</em>) &mdash; &lsquo;were numbered/mustered.&rsquo; <em>p&amacr;qaḏ</em> is the census vocabulary (cf. Num 1:3; 26:2). The Levites from thirty years and above are counted &mdash; the Mosaic standard for Levitical service (Num 4:3, 23, 30: thirty years as the minimum for the wilderness tabernacle). The total is 38,000 (<em>šĕlōš&icirc;m wĕšĕm&ocirc;neh ʾelep</em>). This census functions as the authoritative headcount from which the subsequent organizational assignments are made.</p>",
    "4": "<p><strong>lĕnaṣṣēaḥ</strong> &mdash; &lsquo;to oversee/direct the work of the LORD&rsquo;s house.&rsquo; The root <em>naṣaḥ</em> (to lead, direct, be pre-eminent) is the same root as the Psalm superscription <em>lamnnaṣṣēaḥ</em> (to the director/choirmaster), which appears 55 times in the Psalter. The 24,000 overseers of temple work are drawn from the same verbal root that governs the liturgical direction of Israel&rsquo;s psalms. Six thousand serve as officers (<em>šōṭĕr&icirc;m</em>) and judges (<em>šōpĕṭ&icirc;m</em>) &mdash; the Levites serve both cultic and civil administrative roles.</p>",
    "5": "<p>Four thousand as gatekeepers (<em>šōʿăr&icirc;m</em>); four thousand to praise YHWH with instruments (<em>lĕhall&ecirc;l YHWH bĕkĕl&ecirc; ʾăšer ʿ&amacr;ś&icirc;t&icirc;</em>, &lsquo;with the instruments I made&rsquo;). The <em>Piel</em> infinitive <em>lĕhall&ecirc;l</em> (to praise, from <em>h&amacr;lal</em>) designates an ongoing, intentional act of glorification &mdash; not a one-time event but a continuous vocation. The instruments David &lsquo;made for praise&rsquo; are a specific reference to his invention/commission of new instruments (cf. 2 Chr 29:26-27; Amos 6:5 &lsquo;instruments of music, like David, they have invented for themselves&rsquo;).</p>",
    "6": "<p>David divides them into courses (<em>wayyĕ&#x1E25;all&ecirc;q&ecirc;m dāw&icirc;ḏ maḥlĕq&ocirc;t</em>) corresponding to the three sons of Levi: Gershon (<em>g&ecirc;rš&ocirc;n</em> [also Gershom]), Kohath (<em>qĕhāt</em>), and Merari (<em>mĕr&amacr;r&icirc;</em>). The Hiphil <em>wayyĕ&#x1E25;all&ecirc;q&ecirc;m</em> (he divided/assigned them) signals David&rsquo;s direct administrative action. The three Levitical branches are the organizing principle of the entire OT Levitical system (Num 3-4). The Chronicler traces all subsequent Levitical organization back to this three-fold Sinaitic structure.</p>",
    "7": "<p>The Gershonite clans (<em>lagg&ecirc;rš&ucirc;nn&icirc;</em>): Laadan (<em>lāʿd&amacr;n</em>) and Shimei (<em>šimʿ&icirc;</em>). The Gershonites in Numbers 3-4 were responsible for transporting the tabernacle curtains and coverings. In the temple-era organization of Chronicles, their role shifts to administrative service. The clan name Laadan does not appear in the Pentateuchal Levite lists (Num 3; Exod 6) and may represent a post-Mosaic branch division.</p>",
    "8": "<p>Sons of Laadan: Jehiel the head (<em>r&ocirc;š</em>), Zetham, and Joel. The designation of Jehiel as <em>r&ocirc;š</em> (head, chief) marks him as the senior of the three; the head of a Levitical family had specific responsibilities for coordinating his clan&rsquo;s service rotations. The total of three signals a small sub-clan compared to others in the Levitical system.</p>",
    "9": "<p>Sons of Shimei: Shelomith, Haziel, and Haran &mdash; three. &lsquo;These were the clan heads belonging to Laadan&rsquo; (<em>r&amacr;š&ecirc; h&amacr;ʾāḇ&ocirc;t lĕlāʿd&amacr;n</em>). The closing summary formula &lsquo;these were the heads of the clans belonging to X&rsquo; appears repeatedly through the Levitical lists, marking the completion of a sub-unit. The precise tracking of clan heads ensures that the temple organization can trace each family&rsquo;s assigned duties back to their founding ancestor.</p>",
    "10": "<p>Sons of Shimei: Jahath (<em>yaḥat</em>), Zina (<em>z&icirc;nāh</em>), Jeush (<em>yeʿûš</em>), and Beriah (<em>bĕr&icirc;ʿāh</em>) &mdash; four sons. The name Beriah appears elsewhere as a &lsquo;misfortune-name&rsquo; (cf. Gen 46:17; 1 Chr 7:23 where Beriah is named because &lsquo;evil had come upon his house&rsquo;, <em>ḇĕr&amacr;ʿāh</em>). Whether this Beriah carries the same etymology is uncertain; the name may be a clan-title inherited without the original etymological force.</p>",
    "11": "<p>Jahath was the head (<em>yaḥat r&ocirc;š</em>) and Zizah the second (<em>wĕz&icirc;z&amacr;h haššēn&icirc;</em>). &lsquo;Jeush and Beriah did not have many sons (<em>lōʾ-h&ecirc;rbû b&amacr;n&icirc;m</em>), so they were counted as a single clan (<em>b&ecirc;t-&amacr;ḇ ʾeḥāḏ</em>).&rsquo; The administrative principle: a family too small to function independently is merged with its sibling family for organizational purposes. This pragmatic consolidation reflects real-world temple administration adapting Mosaic structures to population realities.</p>",
    "12": "<p>Sons of Kohath (<em>bĕn&ecirc; qĕhāt</em>): Amram, Izhar, Hebron, and Uzziel &mdash; four clans. The Kohathites were the most honored Levitical branch in the wilderness period: they carried the most sacred objects (the ark, the table, the lampstand, the altars &mdash; Num 3:31) and were numbered first (Num 3:27-32). Amram&rsquo;s prominence (first named) reflects that Moses and Aaron were Amramites.</p>",
    "13": "<p><strong>wayyibb&amacr;d&ecirc;l ʾahr&ocirc;n lĕhaqd&icirc;šô qōḏeš qōḏ&amacr;š&icirc;m</strong> &mdash; &lsquo;Aaron was set apart to consecrate the most holy things.&rsquo; The Niphal <em>wayyibb&amacr;d&ecirc;l</em> (he was set apart) signals divine election through institutional designation; the Hiphil infinitive <em>lĕhaqd&icirc;šô</em> (to consecrate/make holy) establishes Aaron&rsquo;s unique functional identity. <em>qōḏeš qōḏ&amacr;š&icirc;m</em> (most holy things/holy of holies) is the superlative construction: the doubling of <em>qōḏeš</em> creates the Hebrew superlative &mdash; the holiest. Aaron&rsquo;s sons (the priests) &lsquo;to burn incense before YHWH, to minister to him, and to bless in his name forever&rsquo; &mdash; three verbs defining the priestly office: liturgical (incense), ministerial (<em>lĕšār&ecirc;t</em>), and benedictory (<em>lĕḇ&amacr;r&ecirc;ḵ</em>).</p>",
    "14": "<p><strong>môšeh ʾ&icirc;š h&amacr;ʾĕlōh&icirc;m</strong> &mdash; &lsquo;Moses the man of God.&rsquo; <em>ʾ&icirc;š h&amacr;ʾĕlōh&icirc;m</em> is a fixed prophetic title &mdash; used of Moses (Deut 33:1; Josh 14:6; Ps 90:1), Samuel (1 Sam 9:6-10), Elijah (1 Kgs 17:18), Elisha (2 Kgs 4:7), and others. The title is primarily prophetic, not priestly; by designating Moses as <em>ʾ&icirc;š h&amacr;ʾĕlōh&icirc;m</em> rather than priest, the Chronicler signals that Moses&rsquo;s sons belong to the Levites generally, not to the Aaronic priesthood specifically. His sons &lsquo;were counted among the tribe of Levi&rsquo; (<em>n&iqirc;mr&ucirc; ʿal-šeḇet hall&ecirc;w&icirc;</em>) &mdash; placed in the tribe by reckoning rather than the Aaronic office.</p>",
    "15": "<p>Moses had two sons: Gershom (<em>g&ecirc;ršôm</em>) and Eliezer (<em>ʾĕlîʿezer</em>). Both names carry embedded narrative: Gershom means &lsquo;sojourner there&rsquo; (named in Exod 2:22 &lsquo;because I have been a sojourner in a foreign land&rsquo;; <em>g&ecirc;r h&amacr;y&icirc;t&icirc; bĕʾereṣ noḵr&icirc;y&amacr;h</em>); Eliezer means &lsquo;my God is help&rsquo; (named in Exod 18:4 &lsquo;because the God of my father was my help&rsquo;). The names of Moses&rsquo;s sons encode the Exodus theology: sojourn + divine help.</p>",
    "16": "<p>The head of Gershom&rsquo;s descendants was Shebuel (<em>šĕḇ&ucirc;ʾ&ecirc;l r&ocirc;š</em>). Shebuel means &lsquo;return to God&rsquo; (šûḇ + ʾ&ecirc;l) or &lsquo;captive of God&rsquo; (šĕḇî + ʾ&ecirc;l). He is mentioned in 1 Chr 26:24 as &lsquo;in charge of the treasuries&rsquo; &mdash; a significant administrative role. The Mosaic line, though not priestly, holds treasury positions in the temple organization.</p>",
    "17": "<p>Eliezer had one son, Rehabiah (<em>rĕhaḇy&amacr;h&ucirc;</em>), who was the head of his line. Rehabiah means &lsquo;YHWH has enlarged&rsquo; (r&amacr;ḥaḇ + Y&amacr;h). &lsquo;Eliezer had no other sons, but Rehabiah&rsquo;s sons were very numerous&rsquo; (<em>wayyirbû m&ecirc;ʾōḏ</em>). The formula &lsquo;very numerous&rsquo; (<em>m&ecirc;ʾōḏ</em> as intensifier of <em>r&amacr;ḇaḇ</em>) echoes the Abrahamic promise (Gen 17:2 &lsquo;I will multiply you exceedingly&rsquo; &mdash; <em>wĕharb&ecirc;t&icirc; ʾ&ocirc;tĕḵ&amacr; bimʾōḏ mĕʾōḏ</em>). Even in Levitical genealogy, the language of the covenant-multiplication promise reverberates.</p>",
    "18": "<p>The head of Izhar&rsquo;s (<em>yiṣh&amacr;r</em>) line was Shelomith (<em>šĕlōm&icirc;t</em>). Izhar (meaning &lsquo;oil, brightness&rsquo;) was the brother of Amram (Aaron and Moses&rsquo;s father); his descendants form a significant Levitical sub-clan. Shelomith appears in 1 Chr 26:25-28 as the custodian of dedicated gifts &mdash; another significant treasury role, like Moses&rsquo;s descendant Shebuel.</p>",
    "19": "<p>Hebron&rsquo;s sons: Jeriah (<em>yĕr&icirc;yāh&ucirc;</em>) the first, Amariah the second, Jahaziel the third, Jekameam the fourth. The ordinal assignment (first through fourth) is purely administrative: it determines rotation order and precedence in the Levitical service schedule. Hebron was also the name of David&rsquo;s capital before Jerusalem; the coincidence of names (Levitical clan Hebron, city Hebron) is not unusual in Hebrew onomastics where clan names and place names frequently overlap.</p>",
    "20": "<p>Uzziel&rsquo;s (<em>ʿuzz&icirc;ʾ&ecirc;l</em>) sons: Michah (<em>m&icirc;ḵ&amacr;h</em>) the first and Jesiah (<em>yiśś&icirc;y&amacr;h</em>) the second. Uzziel means &lsquo;YHWH is my strength.&rsquo; The Uzzielites in the wilderness period were responsible for specific tabernacle objects (Num 3:29-30). In the temple period their responsibilities shift to the general Kohathite service assignments.</p>",
    "21": "<p>Sons of Merari (<em>mĕr&amacr;r&icirc;</em>): Mahli (<em>maḥl&icirc;</em>) and Mushi (<em>m&ucirc;š&icirc;</em>). Mahli&rsquo;s sons: Eleazar (<em>ʾĕlʿ&amacr;z&amacr;r</em>) and Kish (<em>q&icirc;š</em>). The Merarites in the wilderness transported the tabernacle frames, bars, pillars, and bases (Num 3:36-37) &mdash; the heaviest physical work of the tabernacle service. Their shift to temple service involves different assignments since there is no portable structure to carry.</p>",
    "22": "<p>Eleazar died without sons, leaving only daughters (<em>b&amacr;n&ocirc;t</em>). Their cousins (<em>bĕn&ecirc;-q&icirc;š</em>, the sons of Kish) married them (<em>wayy&iqirc;śś&amacr;ʾ&ucirc;m</em>). The idiom <em>n&amacr;śāʾ ʾiššāh</em> (to take a wife) appears here in shortened form for cousins marrying daughters. The legal principle at work is similar to the daughters of Zelophehad (Num 27; 36): women who inherit in the absence of brothers should marry within their clan to preserve the clan&rsquo;s inheritance. The Merarite clan is preserved through this endogamous marriage.</p>",
    "23": "<p>Mushi&rsquo;s sons: Mahli, Eder (<em>ʿēḏer</em>), and Jeremoth (<em>yĕr&icirc;m&ocirc;t</em>) &mdash; three sons. This completes the Merarite genealogy. The three-fold structure of the Merarite branch (Mahli / Mushi; Eleazar [dies without sons] / Kish; Mahli / Eder / Jeremoth) reflects realistic genealogical variability: some lines die out, some marry cousins to preserve the line, some produce multiple descendants.</p>",
    "24": "<p>&lsquo;These were the sons of Levi by their ancestral houses — the heads of families counted individually, who did the work of the service of the LORD&rsquo;s house, from twenty years old and up (<em>mibben ʿeśr&icirc;m šānh&amacr;h wāmāʿlāh</em>).&rsquo; The age shift &mdash; from thirty (Num 4:3) to twenty &mdash; is introduced here without explanation; the rationale follows in vv25-27. The number twenty is the same threshold used in Num 1:3 for military enrollment and is the age of census-accountability in Israel. Twenty marks adult responsibility; thirty marked the maturity required for full wilderness service.</p>",
    "25": "<p>David&rsquo;s rationale: &lsquo;YHWH the God of Israel has given rest (<em>hēn&icirc;aḥ</em>) to his people, and he lives (<em>wĕyiškōn</em>) in Jerusalem forever.&rsquo; The key terms: <em>nûaḥ</em> (rest, Hiphil: to cause to rest) is the Deuteronomic term for the state of security YHWH promises when Israel is settled (Deut 12:10; 25:19; 1 Kgs 5:4). <em>šākan</em> (to dwell, tabernacle) in the Piel participle <em>wĕyiškōn</em> is the same root as the tabernacle (<em>mišk&amacr;n</em>): YHWH now dwells in permanence rather than in the portable tent. The permanence of the divine dwelling changes the nature of Levitical service.</p>",
    "26": "<p>&lsquo;The Levites would no longer need to carry (<em>lāśēt</em>) the tabernacle (<em>hammišk&amacr;n</em>) or any of its vessels.&rsquo; The infinitive <em>lāśēt</em> (to carry, bear) is the key wilderness-period Levitical verb (Num 4 uses <em>nāśāʾ</em> extensively for the bearing of tabernacle pieces). The Levites were constituted as bearers; now that the tabernacle is permanent in Jerusalem, the primary defining task of Levitical service is obsolete. A new functional identity must be constructed &mdash; which chs. 23-27 do.</p>",
    "27": "<p>&lsquo;By David&rsquo;s final ordinances (<em>ḇĕḏiḇr&ecirc; d&amacr;w&icirc;ḏ h&amacr;ʾaḥărōn&icirc;m</em>), the Levites were counted from twenty years old and up.&rsquo; <em>ʾaḥărōn&icirc;m</em> (last, final) marks these as David&rsquo;s definitive institutional acts. The Chronicler frames the age-lowering as a deliberate Davidic legislative change backed by the logic of the changed circumstances &mdash; not an ad hoc decision but a principled application of the Mosaic system to the new temple context.</p>",
    "28": "<p>&lsquo;Their responsibility was to assist the priests (<em>lĕʿāmōd ʿal-bĕn&ecirc; ʾahr&ocirc;n lĕšār&ecirc;t&amacr;m</em>).&rsquo; The infinitive <em>lĕʿāmōd</em> (to stand) is the posture-verb of covenant service. Deut 10:8: &lsquo;At that time YHWH set apart the tribe of Levi to carry the ark... to stand (<em>lĕʿāmōd</em>) before YHWH, to minister (<em>lĕšār&ecirc;tô</em>) to him, and to bless in his name.&rsquo; Standing before God is the fundamental liturgical posture; the verb recurs through the temple service descriptions to indicate active, attentive ministry as opposed to casual presence.</p>",
    "29": "<p>The Levitical responsibilities include: the rows of bread (<em>lĕleḥem hammaʿăreḵet</em>), fine flour for grain offerings (<em>sōlet lĕminḥāh</em>), unleavened cakes (<em>raqqîq&icirc;m</em>), baked goods (<em>maʿăś&ecirc;h maḥăḇat</em>), and well-mixed offerings (<em>mĕrōḇeḵet</em>). The technical cultic vocabulary is extensive: <em>leḥem hammaʿăreḵet</em> is the showbread/bread of the presence (Lev 24:5-9); <em>minḥāh</em> is the grain offering; <em>raqqîq&icirc;m</em> are the thin cakes of Lev 2:4. The Levites are responsible for the preparation and presentation of the non-animal sacrificial elements.</p>",
    "30": "<p>&lsquo;And to stand (<em>lĕʿāmōd</em>) every morning (<em>bĕkol-bōqer bōqer</em>) to give thanks and praise to YHWH, and likewise every evening (<em>wĕlaʿereḇ</em>).&rsquo; The doubled <em>bōqer bōqer</em> (morning morning) is the distributive construction: every single morning, without exception. This daily rhythm of praise &mdash; morning and evening &mdash; corresponds to the daily burnt offering (<em>tāmîḏ</em>, the continual offering of Exod 29:38-42; Num 28:3-8). The Levitical praise is the human voice accompanying the material sacrifice, constituting the complete act of worship.</p>",
    "31": "<p>&lsquo;To present all burnt offerings (<em>lĕhaqr&icirc;ḇ ʿōlōt</em>) to YHWH on the sabbaths (<em>baššabbāt&ocirc;t</em>), new moons (<em>baḥŏḏāš&icirc;m</em>), and appointed feasts (<em>bammôʿăḏ&icirc;m</em>).&rsquo; The three-fold liturgical calendar (weekly / monthly / annual) frames Levitical service within Israel&rsquo;s complete temporal structure. <em>mōʿēḏ</em> (appointed time, meeting-place) is the term for the full festival cycle and the tent of meeting both: the sacred calendar and the sacred space share the same word, because time and place are both structured by YHWH&rsquo;s appointment.</p>",
    "32": "<p>&lsquo;They were to keep charge (<em>wĕšāmĕr&ucirc; mišmeret</em>) of the tent of meeting, the holy place, and their priestly brothers.&rsquo; <em>mišmeret</em> (charge, watch, duty) is a key priestly-Levitical term (Num 1:53; 3:7-8; 18:3-5): the Levites guard the holy precincts, ensuring that unauthorized persons do not approach and that the sacred objects are properly maintained. The Levites serve both God (the sanctuary) and their brothers (the priests) &mdash; a dual accountability that structures their institutional identity.</p>"
  },
  "24": {
    "1": "<p>The priestly divisions (<em>maḥlĕq&ocirc;t</em>) of Aaron&rsquo;s sons. The chapter opens by noting that Aaron had four sons: Nadab, Abihu, Eleazar, and Ithamar. The four names are standard (Exod 6:23; Lev 10:1; Num 3:2). The mention of all four before the narrative of Nadab and Abihu&rsquo;s death prepares the reader to understand why only 24 courses (not more) emerge from the Aaronic line.</p>",
    "2": "<p><strong>wayyāmutû nad&amacr;ḇ wăʾăḇ&icirc;h&ucirc; lipn&ecirc; ʾăḇ&icirc;hem</strong> &mdash; &lsquo;Nadab and Abihu died before their father.&rsquo; The reference is to Lev 10:1-3 (they offered unauthorized fire, <em>ʾ&ecirc;š z&amacr;r&amacr;h</em>) and Num 3:4. <em>lipn&ecirc; ʾăḇ&icirc;hem</em> (before their father, i.e., while Aaron still lived) is both chronological (they pre-deceased Aaron) and possibly theological (their death &lsquo;before the face of their father&rsquo; is a judgment that strips the priestly succession from their line). They &lsquo;left no sons&rsquo; (<em>ûḇān&icirc;m lōʾ-h&amacr;y&ucirc; l&amacr;hem</em>), so the entire Aaronic succession devolves to Eleazar and Ithamar.</p>",
    "3": "<p>David with Zadok (<em>ṣ&amacr;ḏ&ocirc;q</em>) from Eleazar&rsquo;s line and Ahimelech (<em>ʾăḥ&icirc;melek</em>) from Ithamar&rsquo;s line assigned them (<em>wayye&#x1E25;all&ecirc;q&ecirc;m</em>) according to their appointed duties (<em>kĕp&ecirc;quddāt&amacr;m</em>). The Hiphil <em>wayye&#x1E25;all&ecirc;q&ecirc;m</em> (he distributed them) echoes the Levitical distribution of ch. 23. <em>p&ecirc;quddāh</em> (appointed duty, office) is from <em>p&amacr;qaḏ</em> (to appoint, number, visit). The two high-priestly families (Zadokites and Ithamarites) share the organizational work under David&rsquo;s authority.</p>",
    "4": "<p>More family heads were found among Eleazar&rsquo;s descendants than among Ithamar&rsquo;s, so sixteen heads went to Eleazar, eight to Ithamar. The numerical asymmetry (16:8 = 2:1 ratio) reflects actual demographic reality within the Aaronic line &mdash; Eleazar&rsquo;s descendants were more numerous. The proportion is observed and honored in the organizational structure; the Chronicler does not artificially equalize the assignments.</p>",
    "5": "<p><strong>wayyĕ&#x1E25;all&ecirc;q&ucirc;m b&ecirc;g&ocirc;r&amacr;l&ocirc;t</strong> &mdash; &lsquo;they were assigned by lots.&rsquo; <em>g&ocirc;r&amacr;l</em> (lot) is the instrument of divine determination throughout the OT (Lev 16:8-10; Josh 14-21 for land distribution; Prov 16:33 &lsquo;the lot is cast into the lap, but every decision is from YHWH&rsquo;). The lots ensure that the assignment of priestly courses is YHWH&rsquo;s choice, not a product of David&rsquo;s favoritism or political calculation. Both Eleazar&rsquo;s and Ithamar&rsquo;s descendants are leaders (<em>ś&amacr;r&ecirc; qōḏeš wĕś&amacr;r&ecirc; h&amacr;ʾĕlōh&icirc;m</em>, &lsquo;leaders of the sanctuary and leaders of God&rsquo;) regardless of numerical proportion.</p>",
    "6": "<p>Shemaiah son of Nethaneel, a Levitical scribe (<em>hassōp&ecirc;r hall&ecirc;w&icirc;</em>), records the assignments before the king, the princes, Zadok, Ahimelech, and the heads of the priestly and Levitical families. The presence of a scribe (<em>sōp&ecirc;r</em>) ensures the written, legal permanence of the lot assignments. The audience of witnesses (king, princes, priests, Levites) gives the assignments binding authority across all of Israel&rsquo;s institutional sectors. This bureaucratic precision is characteristic of the Chronicler&rsquo;s administrative concern.</p>",
    "7": "<p>The first lot (<em>hagg&ocirc;r&amacr;l h&amacr;r&icirc;š&ocirc;n</em>) falls to Jehoiarib (<em>yĕhôy&amacr;r&icirc;ḇ</em>); the second to Jedaiah (<em>yĕḏaʿy&amacr;h</em>). Jehoiarib means &lsquo;YHWH pleads/contends&rsquo;; the priestly name encodes the theology of YHWH as Israel&rsquo;s advocate. In the post-exilic period, Jehoiarib became one of the most prominent priestly families (Neh 11:10; 1 Macc 2:1 &mdash; Mattathias the Maccabee is &lsquo;from the sons of Joarib,&rsquo; making the Hasmonean dynasty descendants of the first priestly course).</p>",
    "8": "<p>Third: Harim; fourth: Seorim. The courses continue. <em>Harim</em> means &lsquo;snub-nosed&rsquo; or &lsquo;flat-nosed&rsquo; &mdash; a descriptive physical name (cf. Lev 21:18 where the same term excludes from priestly ministry those with physical defects). The priestly course bearing this name presumably did not associate the name with the disability; it had become a clan designation. Ezra 2:39 and Neh 7:42 list the sons of Harim among the priestly returnees from Babylon.</p>",
    "9": "<p>Fifth: Malchijah; sixth: Mijamin. <em>Malchijah</em> means &lsquo;my king is YHWH&rsquo; &mdash; a theophoric name asserting YHWH&rsquo;s royal sovereignty. <em>Mijamin</em> means &lsquo;from the right hand&rsquo; &mdash; the position of honor and power (Ps 110:1 &lsquo;sit at my right hand&rsquo;). The theophoric names woven into the priestly courses reflect the covenantal theology of their bearers&rsquo; families.</p>",
    "10": "<p>Seventh: Hakkoz (<em>haqqôṣ</em>); eighth: Abijah (<em>ʾăḇ&icirc;yāh</em>). <strong>Abijah is the eighth priestly course.</strong> This is the direct background of Luke 1:5: &lsquo;In the time of Herod king of Judea there was a priest named Zechariah, who belonged to the priestly division of Abijah.&rsquo; The 24 priestly courses established here were still operative in the Second Temple period. Luke 1:8-9 specifies that Zechariah was ministering &lsquo;when his division was on duty.&rsquo; The lot that fell to Abijah in David&rsquo;s organization (v10) is the specific providential structure that placed Zechariah in the temple at the moment of Gabriel&rsquo;s appearance. The eighth course = the eighth two-week rotation of the year.</p>",
    "11": "<p>Ninth: Jeshua (<em>y&ecirc;šûaʿ</em>); tenth: Shecaniah (<em>šĕḵany&amacr;h&ucirc;</em>). <em>y&ecirc;šûaʿ</em> is the same name as Joshua and as Jesus (Gk. <em>I&emacr;sous</em>) &mdash; &lsquo;YHWH saves.&rsquo; The ninth priestly course bears the name that will become the personal name of the great High Priest who supersedes all earthly priestly courses (Heb 7:26-27).</p>",
    "12": "<p>Eleventh: Eliashib (<em>ʾĕlyāš&icirc;ḇ</em>); twelfth: Jakim (<em>y&amacr;q&icirc;m</em>). Eliashib means &lsquo;God restores&rsquo; and became the name of a prominent high priest in Nehemiah&rsquo;s time (Neh 3:1; 12:10; 13:4,7) who unfortunately compromised the temple precincts by allowing Tobiah an enemy of Israel to occupy rooms there. The name that means &lsquo;God restores&rsquo; belongs to a high priest who facilitated desecration.</p>",
    "13": "<p>Thirteenth: Huppah (<em>&#x1E25;upp&amacr;h</em>); fourteenth: Jeshebeab (<em>yĕšĕḇʾāḇ</em>). <em>&#x1E25;upp&amacr;h</em> may relate to <em>&#x1E25;upp&amacr;h</em> (canopy, wedding chamber &mdash; Joel 2:16; Ps 19:5), giving the priestly course a name associated with sacred festivity and marriage. The names of the later courses are less theologically freighted and more likely functional or geographic clan identifiers.</p>",
    "14": "<p>Fifteenth: Bilgah (<em>bilg&amacr;h</em>); sixteenth: Immer (<em>ʾimm&ecirc;r</em>). Immer is a prominent priestly family: Jer 20:1 (Pashhur son of Immer, who struck Jeremiah); Ezra 2:37 (1,052 sons of Immer return from exile); Neh 11:13. The Immer priestly family had significant presence in the exile period and afterward.</p>",
    "15": "<p>Seventeenth: Hezir (<em>&#x1E25;&ecirc;z&icirc;r</em>); eighteenth: Aphses (<em>happiṣṣ&ecirc;ṣ</em>). The name Hezir appears in Neh 10:20 among those who sealed the covenant under Ezra/Nehemiah &mdash; confirming the continuity of these priestly courses through the exile and return.</p>",
    "16": "<p>Nineteenth: Pethahiah (<em>p&ecirc;taḥy&amacr;h&ucirc;</em>); twentieth: Jehezekel (<em>yeḥezq&ecirc;ʾl</em>). <em>Jehezekel</em> (= Ezekiel) means &lsquo;God strengthens.&rsquo; The priestly course name and the great exilic prophet share the same name, though the course was established long before Ezekiel the prophet.</p>",
    "17": "<p>Twenty-first: Jachin (<em>y&amacr;ḵ&icirc;n</em>); twenty-second: Gamul (<em>g&amacr;m&ucirc;l</em>). <em>y&amacr;ḵ&icirc;n</em> means &lsquo;he will establish/make firm&rsquo; &mdash; the same name as the right pillar of Solomon&rsquo;s temple (1 Kgs 7:21; 2 Chr 3:17). The priestly course shares its name with the temple&rsquo;s founding architectural element, a conjunction of nomenclature that was presumably intentional or at least noticed by those who served in the course.</p>",
    "18": "<p>Twenty-third: Delaiah (<em>d&ecirc;lay&amacr;h&ucirc;</em>); twenty-fourth: Maaziah (<em>maʿazy&amacr;h&ucirc;</em>). <em>Maaziah</em> means &lsquo;YHWH is refuge/strength.&rsquo; The twenty-fourth course closes the cycle &mdash; the system then rotates back to Jehoiarib. Twenty-four is the number that will structure the priestly courses, the Levitical musical courses (ch. 25), the Levitical gatekeepers, and the elders around the throne in Rev 4:4 (twenty-four elders). The number encodes the complete institutional structure of Israel&rsquo;s covenant service.</p>",
    "19": "<p><strong>ʾ&ecirc;lleh p&ecirc;quddāt&amacr;m lăḇ&ocirc;ʾ&amacr;m lĕḇ&ecirc;t YHWH kĕmišp&amacr;ṭ&amacr;m</strong> &mdash; &lsquo;These were their appointed duties for entering the LORD&rsquo;s house according to their prescribed procedure.&rsquo; <em>p&ecirc;quddāh</em> (appointed duty) and <em>mišp&amacr;ṭ</em> (procedure, right, judgment) together frame the system as both divinely appointed (<em>p&amacr;qaḏ</em>) and legally ordered (<em>mišp&amacr;ṭ</em>). The procedure traces back to &lsquo;Aaron their father, as YHWH the God of Israel had commanded him&rsquo; (<em>kaʾăšer ṣiww&amacr;h YHWH ʾĕlōh&ecirc; yiśr&amacr;ʾ&ecirc;l</em>) &mdash; connecting the Davidic organization directly to the Mosaic command.</p>",
    "20": "<p>The remaining Levites not in the 24 priestly courses: from Amram&rsquo;s line, Shubael; from Shubael&rsquo;s line, Jehdeiah. This second list (vv20-31) enumerates the Levites organized alongside the priestly courses by the same lot process (v31). The structural symmetry &mdash; priests organized by lot, Levites organized by lot &mdash; ensures that the entire institutional leadership is appointed by YHWH&rsquo;s determination.</p>",
    "21": "<p>From Rehabiah&rsquo;s line: Isshiah the head (<em>r&ocirc;š</em>). Rehabiah was the son of Eliezer the son of Moses (23:17) &mdash; the line of Moses continues in temple administration. The Mosaic descendants do not become priests (only Aaronic sons serve at the altar) but they hold prominent Levitical leadership positions, maintaining the honor of Moses&rsquo;s lineage within the temple system.</p>",
    "22": "<p>From the Izharite line: Shelomoth; from Shelomoth&rsquo;s line, Jahath (<em>yaḥat</em>). The Izharites are Kohathites descended from Izhar, brother of Amram. Their temple role focuses on treasury duties (1 Chr 26:25-28).</p>",
    "23": "<p>Hebron&rsquo;s sons listed in order: Jeriah the first, Amariah the second, Jahaziel the third, Jekameam the fourth. This corresponds to 23:19 &mdash; the list is reproduced to assign the Hebronites their specific lot position within the broader Levitical rotation. The parallel structure between ch. 23 (clan list) and ch. 24 (lot assignments) is the Chronicler&rsquo;s characteristic method of cross-referencing within his institutional history.</p>",
    "24": "<p>From Uzziel&rsquo;s line: Michah; from Michah&rsquo;s line, Shamir (<em>šām&icirc;r</em>). <em>šāmir</em> means &lsquo;thorn, flint, emery stone&rsquo; &mdash; a hard-stone name suggesting endurance or sharpness. The Uzzielites continue through the post-exilic period as an identifiable Levitical family.</p>",
    "25": "<p>Michah&rsquo;s brother was Isshiah; Isshiah&rsquo;s son was Zechariah (<em>zĕḵary&amacr;h&ucirc;</em>). Zechariah means &lsquo;YHWH remembers&rsquo; &mdash; one of the most common theophoric names in the OT, appearing 30+ times for different individuals including the post-exilic prophet Zechariah whose book closes with the vision of YHWH as king over all the earth (Zech 14:9).</p>",
    "26": "<p>Sons of Merari: Mahli and Mushi. And from Jaaziah (<em>yaʿazîy&amacr;h&ucirc;</em>) &mdash; another of Merari&rsquo;s descendants &mdash; his son Beno (<em>b&ecirc;nô</em>, &lsquo;his son&rsquo;). <em>Beno</em> may be a personal name that happens to look like the common noun <em>b&ecirc;n</em> (son), or the text may be using &lsquo;his son&rsquo; as a placeholder for a name not preserved. The LXX and some commentators read <em>Beno</em> as a proper name; the MT is ambiguous.</p>",
    "27": "<p>Jaaziah&rsquo;s descendants: Beno, Shoham (<em>šōham</em>), Zaccur (<em>zakkûr</em>), and Ibri (<em>ʿiḇr&icirc;</em>). <em>ʿiḇr&icirc;</em> means &lsquo;Hebrew&rsquo; or &lsquo;one who crosses over&rsquo; &mdash; a Levite whose name is the adjective-form of Israel&rsquo;s national identity. The name may preserve a tradition of this branch&rsquo;s particular identity or role.</p>",
    "28": "<p>Mahli&rsquo;s son Eleazar had no sons (<em>lōʾ-h&amacr;y&ucirc; l&ocirc; b&amacr;n&icirc;m</em>) &mdash; a second instance of a priestly/Levitical line ending without male heirs (cf. 23:22). The repeated notation of heirless deaths without resolution (in 23:22 the daughters marry cousins; here no solution is mentioned) reflects honest genealogical record-keeping rather than theological idealization.</p>",
    "29": "<p>Kish&rsquo;s line: his son Jerahmeel (<em>yĕra&#x1E25;mĕʾ&ecirc;l</em>). Jerahmeel means &lsquo;God will have compassion/mercy&rsquo; (<em>r&amacr;&#x1E25;am</em> + ʾ&ecirc;l). The Jerahmeelites appear in 1 Sam 27:10 as a people in the southern Negev, possibly a non-Israelite group absorbed into Judah. This Merarite Jerahmeel is a Levitical official, not connected to the Negev Jerahmeelites.</p>",
    "30": "<p>Mushi&rsquo;s sons: Mahli, Eder, and Jerimoth (<em>yĕr&icirc;m&ocirc;t</em>). &lsquo;These were the Levites organized by their ancestral families&rsquo; (<em>ʾēlleh b&ecirc;n&ecirc; hall&ecirc;w&icirc; lĕḇ&ecirc;t ʾăḇōt&amacr;m</em>) &mdash; the closing formula for the Levitical section before the lot-casting of v31.</p>",
    "31": "<p>&lsquo;These also cast lots (<em>wayyapîl&ucirc; gam-h&ecirc;mmāh g&ocirc;r&amacr;l&ocirc;t</em>) alongside their priestly brothers the sons of Aaron, before King David, Zadok, Ahimelech, and the heads of the priestly and Levitical families.&rsquo; The symmetry is deliberate: just as the priestly courses are determined by lot, so are the Levitical assignments. The lot places both priests and Levites under divine rather than human appointment. <em>gam-h&ecirc;mmāh</em> (they also) signals the inclusive equity: the same divine process governs all Israel&rsquo;s institutional leadership, &lsquo;the head of the family as well as his younger brother alike&rsquo; (<em>k&amacr;ḵ lĕqāṭōn kĕg&amacr;ḏ&ocirc;l r&amacr;š-ʾāḇ k&ecirc;ʾāḥ&icirc;w</em>).</p>"
  },
  "25": {
    "1": "<p>David and the military commanders (<em>ś&amacr;r&ecirc; haṣṣ&amacr;ḇ&amacr;ʾ</em>) set apart for service the sons of Asaph, Heman, and Jeduthun &lsquo;who were to prophesy (<em>hannibb&ecirc;ʾ&icirc;m</em>) with lyres, harps, and cymbals.&rsquo; The Hithpael participle <em>hannibb&ecirc;ʾ&icirc;m</em> (those who prophesy) applies the prophetic vocabulary to musicians. The Hithpael of <em>n&amacr;ḇ&amacr;ʾ</em> (to prophesy) describes an ecstatic or inspired state (cf. 1 Sam 10:5-6 where the prophetic band plays instruments and prophesies). The temple musicians&rsquo; work is not merely artistic performance but a form of inspired proclamation &mdash; &lsquo;a manifestation of the Spirit analogous to prophetic speech&rsquo; (cf. 1 Cor 14:26 &lsquo;when you come together... each one has a... revelation&rsquo;).</p>",
    "2": "<p>From Asaph&rsquo;s line: Zaccur, Joseph, Nethaniah, and Asarelah &mdash; Asaph&rsquo;s sons, serving under Asaph&rsquo;s direction (<em>ʿal-y&ecirc;ḏê ʾ&amacr;s&amacr;p</em>). The idiom <em>ʿal-y&ecirc;ḏê</em> (lit. &lsquo;upon the hands of&rsquo;) means &lsquo;under the supervision/direction of.&rsquo; Asaph prophesied (<em>hannabb&ecirc;ʾ ʿal-y&ecirc;ḏê hammelek</em>) &lsquo;under the direction of the king.&rsquo; The chain of authority flows from YHWH → David → Asaph → his sons. Asaph is the author of Psalms 73&ndash;83 in the canonical Psalter; his role as temple musician and prophet explains why psalms bear his name.</p>",
    "3": "<p>From Jeduthun&rsquo;s line: his six sons serve under Jeduthun&rsquo;s direction &lsquo;with the lyre, to prophesy in giving thanks and praising YHWH&rsquo; (<em>ʿal-yĕd&ecirc; y&ecirc;d&ucirc;t&ucirc;n bannĕḇ&icirc;yim bĕḵinnôr l&amacr;môḏōt ûl&amacr;hall&ecirc;l YHWH</em>). The prepositional phrase <em>l&amacr;môḏōt ûl&amacr;hall&ecirc;l</em> (to give thanks and to praise) defines the prophetic content of the music: thankgiving (<em>y&amacr;ḏāh</em>, Hiphil infinitive) and praise (<em>h&amacr;lal</em>, Piel infinitive). Temple prophetic music is functionally oriented toward <em>t&ocirc;ḏāh</em> (thanksgiving offering/declaration) and <em>hll</em> (praise) &mdash; the two poles of the Levitical worship vocabulary.</p>",
    "4": "<p>From Heman&rsquo;s line: his sons Bukkiah, Mattaniah, Uzziel, Shebuel, Jerimoth, Hananiah, Hanani, Eliathah, Giddalti, Romamtiezer, Joshbekashah, Mallothi, Hothir, Mahazioth. These fourteen names have been noted by scholars as forming, with some emendation, a prayer-poem: &lsquo;I have been favored [by God]; have mercy on me, Lord; have mercy on me; Thou art my God, I praise Thee, I raise up [the oracle]; Thou sittest amid adversity; I see [visions] abundantly; and I spoke, by the grace of God, for the exaltation of the Horn.&rsquo; If this reading is correct (it is debated), Heman&rsquo;s fourteen sons&rsquo; names are encoded liturgical language.</p>",
    "5": "<p><strong>&hcirc;&ecirc;m&amacr;n &#x1E25;&ocirc;zeh hammelek</strong> &mdash; &lsquo;Heman the king&rsquo;s seer.&rsquo; <em>&#x1E25;&ocirc;zeh</em> is the participle of <em>&#x1E25;&amacr;z&amacr;h</em> (to see, behold in vision) &mdash; a seer receives visual prophetic revelation. The same term describes Gad (2 Sam 24:11; 1 Chr 21:9), Asaph (2 Chr 29:30 &lsquo;Asaph the seer&rsquo;), and Jeduthun (2 Chr 35:15 &lsquo;Jeduthun the seer&rsquo;). All three temple musician-leaders are seers. &lsquo;Given according to God&rsquo;s word (<em>dibr&ecirc; h&amacr;ʾĕlōh&icirc;m</em>) to exalt his horn (<em>lĕr&ucirc;m qeren</em>).&rsquo; <em>r&ucirc;m qeren</em> (to raise the horn) is the idiom for bestowing strength and honor: the horn raised high = exaltation (cf. Ps 89:17; 92:10; 1 Sam 2:10 &lsquo;YHWH will exalt the horn of his anointed&rsquo;). God gave Heman fourteen sons to exalt YHWH&rsquo;s glory.</p>",
    "6": "<p>&lsquo;All these sons served under their father&rsquo;s direction (<em>ʿal-y&ecirc;ḏ&ecirc; ʾăḇ&icirc;hem</em>) in music for the LORD&rsquo;s house, with cymbals (<em>bĕmĕṣilt&amacr;yim</em>), lyres (<em>ḇinnĕḇ&amacr;l&icirc;m</em>), and harps (<em>ûḇĕkinn&ocirc;r&ocirc;t</em>).&rsquo; The three instruments enumerated &mdash; cymbals, lyres, harps &mdash; are the characteristic temple orchestra. The term <em>mĕṣiltayim</em> (cymbals) appears only in Chronicles and Ezra-Nehemiah for the specifically Levitical cymbal-instrument (as distinct from <em>ṣĕlṣĕl&icirc;m</em> used in other contexts). Ps 150:4-5 employs the same instruments in a concluding doxology.</p>",
    "7": "<p>&lsquo;Including their skilled fellow musicians (<em>mĕḇ&icirc;n&icirc;m</em>) who were trained in the LORD&rsquo;s songs (<em>mĕlummĕḏ&icirc;m š&icirc;r YHWH</em>), the total was two hundred eighty-eight.&rsquo; <em>mĕḇ&icirc;n</em> (discerning, understanding, skilled) is the Hiphil participle of <em>b&icirc;n</em> (to understand, discern). The 288 comes from 24 courses × 12 members each; the mathematical structure mirrors the 24 priestly courses. <em>mĕlummĕḏ&icirc;m</em> (trained, taught) is the Pual participle of <em>l&amacr;mad</em> (to learn, teach) &mdash; the same root as the noun <em>talmîḏ</em> (disciple/student) in the following verse.</p>",
    "8": "<p>&lsquo;They cast lots for their duty assignments, regardless of rank (<em>kĕqāṭōn k&ecirc;g&amacr;ḏ&ocirc;l</em>), whether teacher or student (<em>m&ecirc;ḇ&icirc;n ʿim-talmîḏ</em>).&rsquo; <em>talmîḏ</em> (disciple, student) is one of the rarest words in the OT &mdash; appearing only here and in Isa 8:16 (&lsquo;bind up the testimony, seal the law among my disciples&rsquo;). The term that becomes central in NT usage (the Twelve as Jesus&rsquo; <em>math&emacr;tai</em>, Gk. translation of talmîḏ) has its OT root in temple music education. The lot ensures that the divine appointment falls &lsquo;whether great or small, teacher or student&rsquo; &mdash; the lot is democratic in the sense that it reflects YHWH&rsquo;s choice alone.</p>",
    "9": "<p>The first lot fell to Joseph from Asaph&rsquo;s family (<em>yôsēp libnê-ʾ&amacr;s&amacr;p</em>) &mdash; he and his brothers and sons, twelve. The organizational unit of each course is twelve (the number of the tribes, the complete Israel). The total of 24 × 12 = 288 encodes both the complete liturgical cycle (24) and the complete Israel (12). Each course serves for one week in a two-week rotation pattern (24 courses × 2 = 48 weeks; the remaining weeks fall at the three pilgrimage festivals when all priests/Levites serve together).</p>",
    "10": "<p>The second lot fell to Gedaliah (<em>gĕdaly&amacr;h&ucirc;</em>) &mdash; he and his brothers and sons, twelve. Gedaliah means &lsquo;YHWH is great.&rsquo; The name is also borne by the ill-fated governor of Judah after the Babylonian conquest (2 Kgs 25:22-25; Jer 40-41). The musician Gedaliah and the governor Gedaliah share a name that expresses the same theological confession; the name&rsquo;s meaning endures through both uses.</p>",
    "11": "<p>Third lot: Zaccur (<em>zakkûr</em>), he and his brothers and sons, twelve. Zaccur means &lsquo;remembered&rsquo; (Niphal participle of <em>z&amacr;kar</em>) &mdash; the one whom [YHWH] remembers. The same name appears among the gatekeepers (26:2) and in the post-exilic period (Neh 3:2; 10:12; 13:13). The lot-assignment formula (third lot / name / family size twelve) will repeat with minor variation through v31.</p>",
    "12": "<p>Fourth lot: Izri (<em>yiṣr&icirc;</em>), he and his brothers and sons, twelve. Izri does not appear in the earlier Jeduthun list (v3, where the parallel slot has &lsquo;Zeri&rsquo; <em>ṣer&icirc;</em>). The variation (Izri/Zeri) is likely a spelling variant: in Hebrew the letters <em>yod</em>-<em>zayin</em>-<em>resh</em>-<em>yod</em> can be confused with <em>zayin</em>-<em>resh</em>-<em>yod</em>. The LXX and other textual witnesses show variation here; the variant names are the same course.</p>",
    "13": "<p>Fifth lot: Nethaniah (<em>nĕtany&amacr;h&ucirc;</em>), he and his brothers and sons, twelve. Nethaniah means &lsquo;YHWH has given.&rsquo; The same name is borne by Ishmael son of Nethaniah, who assassinated Gedaliah the governor (2 Kgs 25:25; Jer 40:14). The Levitical musician and the violent Ishmael share the same patronym; the name represents a common Second Temple-period theological affirmation.</p>",
    "14": "<p>Sixth lot: Bukkiah (<em>buqqiyy&amacr;h&ucirc;</em>), he and his brothers and sons, twelve. Bukkiah means &lsquo;proven/tried by YHWH&rsquo; (from <em>b&amacr;qaʿ</em> or <em>b&amacr;qaq</em>). The name is unique to this musical family in the OT.</p>",
    "15": "<p>Seventh lot: Jesharelah (<em>yĕšareʾ&ecirc;l&amacr;h</em>), he and his brothers and sons, twelve. The name does not appear elsewhere in this exact form. In the earlier list (v2) Asaph&rsquo;s son is called &lsquo;Asarelah&rsquo; (<em>ʾăśarʾ&ecirc;l&amacr;h</em>), which is likely the same name with a different spelling of the theophoric element. The variant spellings within the same chapter reflect the fluidity of pre-standardized Hebrew orthography.</p>",
    "16": "<p>Eighth lot: Jeshaiah (<em>yĕšaʿy&amacr;h&ucirc;</em>), he and his brothers and sons, twelve. Jeshaiah means &lsquo;YHWH is salvation&rsquo; &mdash; the same semantic content as Isaiah and Joshua/Jesus. The theophoric name group <em>y&amacr;šaʿ</em> (to save) + YHWH produces the vocabulary of Israel&rsquo;s salvation hope.</p>",
    "17": "<p>Ninth lot: Mattaniah (<em>mattany&amacr;h&ucirc;</em>), he and his brothers and sons, twelve. Mattaniah means &lsquo;gift of YHWH.&rsquo; This is the original name of King Zedekiah before Nebuchadnezzar changed it (2 Kgs 24:17). The Levitical musician and the last king of Judah share the same birth name; Mattaniah = &lsquo;YHWH&rsquo;s gift&rsquo; while Zedekiah = &lsquo;YHWH is my righteousness.&rsquo;</p>",
    "18": "<p>Tenth lot: Shimei (<em>šimʿ&icirc;</em>), he and his brothers and sons, twelve. Shimei means &lsquo;YHWH has heard.&rsquo; The name appears for many OT figures including the Benjaminite who cursed David (2 Sam 16:5-13) and the Levite who led post-exilic revival in Ezra 10:23.</p>",
    "19": "<p>Eleventh lot: Azareel (<em>ʿăzarʾ&ecirc;l</em>), he and his brothers and sons, twelve. Azareel means &lsquo;God has helped&rsquo; (same as Azarel or Azriel). In v2 Asaph&rsquo;s son is listed by a different name for this slot, suggesting that Azareel may be an alternate name or that the course took the name of its original head&rsquo;s family designation rather than his birth-name.</p>",
    "20": "<p>Twelfth lot: Hashabiah (<em>&#x1E25;ăšaḇy&amacr;h&ucirc;</em>), he and his brothers and sons, twelve. Hashabiah means &lsquo;YHWH has considered/reckoned&rsquo; (from <em>&#x1E25;&amacr;šaḇ</em>, to think, plan, reckon). The name appears 12 times in Chronicles, Ezra, and Nehemiah for various Levitical officials &mdash; it was clearly a common name in Levitical families of the post-exilic period.</p>",
    "21": "<p>Thirteenth lot: Shubael (<em>šûḇāʾ&ecirc;l</em>), he and his brothers and sons, twelve. Shubael means &lsquo;return to God&rsquo; or &lsquo;captive of God.&rsquo; This is identified in 23:16 as the head of Gershom&rsquo;s (Moses&rsquo;s son&rsquo;s) line &mdash; the musician Shubael descends from Moses&rsquo;s grandson, making this musical course carry the Mosaic lineage into the musical division.</p>",
    "22": "<p>Fourteenth lot: Mattithiah (<em>mattity&amacr;h&ucirc;</em>), he and his brothers and sons, twelve. Mattithiah means &lsquo;gift of YHWH&rsquo; (from <em>n&amacr;tan</em> + Y&amacr;h, differently constructed from Mattaniah). Mattithiah appears in Ezra 10:43 as one who married a foreign woman and agreed to put her away, and in Neh 8:4 as one who stood beside Ezra as he read the law &mdash; a significant liturgical role.</p>",
    "23": "<p>Fifteenth lot: Jeremoth (<em>yĕr&ecirc;m&ocirc;t</em>), he and his brothers and sons, twelve. Jeremoth means &lsquo;heights&rsquo; or &lsquo;high places.&rsquo; In v3&rsquo;s parallel list of Jeduthun&rsquo;s sons, the corresponding name is &lsquo;Jeshaiah&rsquo; &mdash; either a different son was named to this course in the lot assignment, or the names represent variants.</p>",
    "24": "<p>Sixteenth lot: Hananiah (<em>&#x1E25;ănany&amacr;h&ucirc;</em>), he and his brothers and sons, twelve. Hananiah means &lsquo;YHWH is gracious.&rsquo; Among the most common OT theophoric names, Hananiah appears for the three friends of Daniel (Hananiah = Shadrach in Dan 1:6-7), showing that the name bridges the musical and the prophetic streams of Israelite tradition.</p>",
    "25": "<p>Seventeenth lot: Joshbekashah (<em>yošbeq&amacr;šāh</em>), he and his brothers and sons, twelve. The name is unusual and its meaning uncertain; it may mean &lsquo;dwelling in hardship&rsquo; or &lsquo;sitting in a hard place.&rsquo; It appears only in this musical context.</p>",
    "26": "<p>Eighteenth lot: Hanani (<em>&#x1E25;ăn&amacr;n&icirc;</em>), he and his brothers and sons, twelve. Hanani means &lsquo;gracious&rsquo; or &lsquo;YHWH is gracious.&rsquo; Hanani the seer rebuked King Asa for trusting Syria rather than YHWH (2 Chr 16:7-10) and was imprisoned for it; Nehemiah&rsquo;s brother Hanani brought news of Jerusalem&rsquo;s broken walls (Neh 1:2). The name&rsquo;s frequency reflects its theological content.</p>",
    "27": "<p>Nineteenth lot: Mallothi (<em>mall&ocirc;t&icirc;</em>), he and his brothers and sons, twelve. Mallothi means &lsquo;I have spoken&rsquo; or &lsquo;utterance&rsquo; &mdash; a verb-form name from <em>mill&ecirc;l</em> (to speak). The speaking-name for a musician who serves in prophetic musical proclamation has an internal coherence: the musician speaks YHWH&rsquo;s word through the medium of sacred song.</p>",
    "28": "<p>Twentieth lot: Eliathah (<em>ʾĕly&amacr;t&amacr;h</em>), he and his brothers and sons, twelve. Eliathah means &lsquo;my God has come&rsquo; or &lsquo;God appears.&rsquo; The name encodes the theology of divine presence &mdash; God comes, God is present &mdash; which is the fundamental premise of the temple itself.</p>",
    "29": "<p>Twenty-first lot: Hothir (<em>h&ocirc;t&icirc;r</em>), he and his brothers and sons, twelve. Hothir means &lsquo;abundance, surplus, excess&rsquo; (from <em>yātar</em>, to leave over, be abundant). The name of abundance for one of the temple&rsquo;s musicians gestures toward the worship theme of overflowing gratitude.</p>",
    "30": "<p>Twenty-second lot: Giddalti (<em>giddalt&icirc;</em>), he and his brothers and sons, twelve. Giddalti means &lsquo;I have magnified/exalted&rsquo; (Piel perfect of <em>g&amacr;ḏal</em>: to make great, magnify). The first-person verb as a name is a testimony-form: &lsquo;I have magnified [the Lord].&rsquo; Ps 34:3 &lsquo;magnify YHWH with me&rsquo; (<em>gadd&ecirc;l&ucirc; YHWH ʾitt&icirc;</em>) uses the same root in the imperative.</p>",
    "31": "<p>Twenty-third lot: Mahazioth (<em>ma&#x1E25;ăzy&ocirc;t</em>); twenty-fourth lot: Romamtiezer (<em>r&ocirc;mamtîʿezer</em>). Romamtiezer is the most distinctive name in the list &mdash; it means &lsquo;I have exalted his help&rsquo; or &lsquo;exaltation of help.&rsquo; The root <em>r&ucirc;m</em> (to exalt) + <em>ʿezer</em> (help) combines the exaltation-vocabulary of v5 (<em>lĕr&ucirc;m qeren</em>, to exalt the horn) with the help-vocabulary of the divine name &lsquo;Eliezer&rsquo; (my God is help) in 23:15. The twenty-fourth course closes the musical cycle on a note of exaltation and divine assistance &mdash; both themes central to Levitical temple worship.</p>"
  }
}

def main():
    c = load_comm('mkt-original', '1chronicles')
    merge_comm(c, CHRON1)
    save_comm('mkt-original', '1chronicles', c)
    count = sum(len(v) for v in CHRON1.values())
    print(f'1chronicles mkt-original ch 23-25: wrote {count} verses')

if __name__ == '__main__':
    main()
